(()=>{const $=(r,s)=>r.querySelector(s);const enc=s=>btoa(unescape(encodeURIComponent(s)));const dec=s=>decodeURIComponent(escape(atob(s.trim())));function stats(s){return{Input:s.length,Lines:s.split(/\r?\n/).length,Words:(s.match(/\S+/g)||[]).length};}function showStats(r,o){$(r,'[data-stats]').innerHTML=Object.entries(o).map(([k,v])=>`<div><strong>${v}</strong><span>${k}</span></div>`).join('')}function run(root){const mode=root.dataset.devMode,input=$(root,'[data-dev-input]')?.value||'';let out='',st=stats(input);try{if(mode==='json-format'){const o=JSON.parse(input);out=JSON.stringify(o,null,2);st={...st,Type:Array.isArray(o)?'Array':typeof o,Keys:Array.isArray(o)?o.length:Object.keys(o||{}).length};}else if(mode==='json-minify'){out=JSON.stringify(JSON.parse(input));}else if(mode==='json-validate'){const o=JSON.parse(input);out='Valid JSON\n\n'+JSON.stringify({type:Array.isArray(o)?'array':typeof o,topLevelSize:Array.isArray(o)?o.length:Object.keys(o||{}).length},null,2);}else if(mode==='b64-enc')out=enc(input);else if(mode==='b64-dec')out=dec(input);else if(mode==='url-enc')out=encodeURIComponent(input);else if(mode==='url-dec')out=decodeURIComponent(input);else if(mode==='jwt'){const parts=input.trim().split('.');if(parts.length<2)throw new Error('JWT should contain at least header.payload');const parse=p=>JSON.stringify(JSON.parse(dec(p.replace(/-/g,'+').replace(/_/g,'/'))),null,2);out='Header:\n'+parse(parts[0])+'\n\nPayload:\n'+parse(parts[1])+'\n\nSignature present: '+Boolean(parts[2]);}else if(mode==='uuid'){const n=Math.max(1,Math.min(1000,Number($(root,'[data-count]')?.value||10)));out=Array.from({length:n},()=>crypto.randomUUID()).join('\n');st={Generated:n};}else if(mode==='password'){const len=Math.max(6,Math.min(128,Number($(root,'[data-length]')?.value||20))),n=Math.max(1,Math.min(100,Number($(root,'[data-count]')?.value||5)));let chars='';if($(root,'[data-upper]')?.checked)chars+='ABCDEFGHJKLMNPQRSTUVWXYZ';if($(root,'[data-lower]')?.checked)chars+='abcdefghijkmnopqrstuvwxyz';if($(root,'[data-digits]')?.checked)chars+='23456789';if($(root,'[data-symbols]')?.checked)chars+='!@#$%^&*_-+=';if(!chars)chars='abcdefghijklmnopqrstuvwxyz';const bytes=new Uint32Array(len*n);crypto.getRandomValues(bytes);out=Array.from({length:n},(_,i)=>Array.from({length:len},(_,j)=>chars[bytes[i*len+j]%chars.length]).join('')).join('\n');st={Generated:n,Length:len};}}catch(e){out='Error: '+e.message}$(root,'[data-dev-output]').value=out;showStats(root,st);$(root,'[data-status]').textContent=`Output ${out.length.toLocaleString()} characters.`;}document.addEventListener('click',e=>{const r=e.target.closest('.dev-core-tool');if(!r)return;if(e.target.matches('[data-dev-example]')){const box=$(r,'[data-dev-input]');if(box)box.value=e.target.dataset.example||'';run(r);}if(e.target.matches('[data-dev-run]'))run(r);if(e.target.matches('[data-dev-copy]'))navigator.clipboard.writeText($(r,'[data-dev-output]').value);if(e.target.matches('[data-dev-download]')){const b=new Blob([$(r,'[data-dev-output]').value],{type:'text/plain'}),a=document.createElement('a');a.href=URL.createObjectURL(b);a.download=`pawstool-${r.dataset.toolSlug}.txt`;a.click()}if(e.target.matches('[data-dev-clear]')){r.querySelectorAll('textarea').forEach(x=>x.value='');$(r,'[data-stats]').innerHTML='';$(r,'[data-status]').textContent='Cleared.';}});document.addEventListener('input',e=>{const r=e.target.closest('.dev-core-tool');if(r&&e.target.tagName==='TEXTAREA')run(r)});})();